import{_ as t,o as i,c as s,a2 as n}from"./chunks/framework.CuteRReP.js";const c=JSON.parse('{"title":"cm-debugging","description":"Use when encountering any bug, test failure, or unexpected behavior, before proposing fixes","frontmatter":{"title":"cm-debugging","description":"Use when encountering any bug, test failure, or unexpected behavior, before proposing fixes","keywords":["cm-debugging","cody master","ai skill"],"robots":"index, follow"},"headers":[],"relativePath":"skills/cm-debugging.md","filePath":"skills/cm-debugging.md"}'),a={name:"skills/cm-debugging.md"};function o(l,e,r,p,u,d){return i(),s("div",null,[...e[0]||(e[0]=[n(`<blockquote><p><strong>📋 Full Skill Source</strong> — This is the complete, unedited SKILL.md file. Nothing is hidden or summarized.</p></blockquote><p><a href="./">← Back to Skills Library</a></p><h1 id="systematic-debugging" tabindex="-1">Systematic Debugging <a class="header-anchor" href="#systematic-debugging" aria-label="Permalink to &quot;Systematic Debugging&quot;">​</a></h1><h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>Random fixes waste time and create new bugs. Quick patches mask underlying issues.</p><p><strong>Core principle:</strong> ALWAYS find root cause before attempting fixes. Symptom fixes are failure.</p><p><strong>Violating the letter of this process is violating the spirit of debugging.</strong></p><h2 id="the-iron-law" tabindex="-1">The Iron Law <a class="header-anchor" href="#the-iron-law" aria-label="Permalink to &quot;The Iron Law&quot;">​</a></h2><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>NO FIXES WITHOUT ROOT CAUSE INVESTIGATION FIRST</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>If you haven&#39;t completed Phase 1, you cannot propose fixes.</p><h2 id="when-to-use" tabindex="-1">When to Use <a class="header-anchor" href="#when-to-use" aria-label="Permalink to &quot;When to Use&quot;">​</a></h2><p>Use for ANY technical issue:</p><ul><li>Test failures</li><li>Bugs in production</li><li>Unexpected behavior</li><li>Performance problems</li><li>Build failures</li><li>Integration issues</li></ul><p><strong>Use this ESPECIALLY when:</strong></p><ul><li>Under time pressure (emergencies make guessing tempting)</li><li>&quot;Just one quick fix&quot; seems obvious</li><li>You&#39;ve already tried multiple fixes</li><li>Previous fix didn&#39;t work</li><li>You don&#39;t fully understand the issue</li></ul><p><strong>Don&#39;t skip when:</strong></p><ul><li>Issue seems simple (simple bugs have root causes too)</li><li>You&#39;re in a hurry (rushing guarantees rework)</li><li>Manager wants it fixed NOW (systematic is faster than thrashing)</li></ul><h2 id="the-four-phases" tabindex="-1">The Four Phases <a class="header-anchor" href="#the-four-phases" aria-label="Permalink to &quot;The Four Phases&quot;">​</a></h2><p>You MUST complete each phase before proceeding to the next.</p><h3 id="phase-1-root-cause-investigation" tabindex="-1">Phase 1: Root Cause Investigation <a class="header-anchor" href="#phase-1-root-cause-investigation" aria-label="Permalink to &quot;Phase 1: Root Cause Investigation&quot;">​</a></h3><p><strong>BEFORE attempting ANY fix:</strong></p><ol><li><p><strong>Read Error Messages Carefully</strong></p><ul><li>Don&#39;t skip past errors or warnings</li><li>They often contain the exact solution</li><li>Read stack traces completely</li><li>Note line numbers, file paths, error codes</li></ul></li><li><p><strong>Reproduce Consistently</strong></p><ul><li>Can you trigger it reliably?</li><li>What are the exact steps?</li><li>Does it happen every time?</li><li>If not reproducible → gather more data, don&#39;t guess</li></ul></li><li><p><strong>Check Recent Changes</strong></p><ul><li>What changed that could cause this?</li><li>Git diff, recent commits</li><li>New dependencies, config changes</li><li>Environmental differences</li></ul></li><li><p><strong>Gather Evidence in Multi-Component Systems</strong></p><p><strong>WHEN system has multiple components (CI → build → signing, API → service → database):</strong></p><p><strong>BEFORE proposing fixes, add diagnostic instrumentation:</strong></p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>For EACH component boundary:</span></span>
<span class="line"><span>  - Log what data enters component</span></span>
<span class="line"><span>  - Log what data exits component</span></span>
<span class="line"><span>  - Verify environment/config propagation</span></span>
<span class="line"><span>  - Check state at each layer</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Run once to gather evidence showing WHERE it breaks</span></span>
<span class="line"><span>THEN analyze evidence to identify failing component</span></span>
<span class="line"><span>THEN investigate that specific component</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br></div></div></li><li><p><strong>Trace Data Flow</strong></p><p><strong>WHEN error is deep in call stack:</strong></p><ul><li>Where does bad value originate?</li><li>What called this with bad value?</li><li>Keep tracing up until you find the source</li><li>Fix at source, not at symptom</li></ul></li></ol><h3 id="phase-2-pattern-analysis" tabindex="-1">Phase 2: Pattern Analysis <a class="header-anchor" href="#phase-2-pattern-analysis" aria-label="Permalink to &quot;Phase 2: Pattern Analysis&quot;">​</a></h3><p><strong>Find the pattern before fixing:</strong></p><ol><li><p><strong>Find Working Examples</strong></p><ul><li>Locate similar working code in same codebase</li><li>What works that&#39;s similar to what&#39;s broken?</li></ul></li><li><p><strong>Compare Against References</strong></p><ul><li>If implementing pattern, read reference implementation COMPLETELY</li><li>Don&#39;t skim - read every line</li><li>Understand the pattern fully before applying</li></ul></li><li><p><strong>Identify Differences</strong></p><ul><li>What&#39;s different between working and broken?</li><li>List every difference, however small</li><li>Don&#39;t assume &quot;that can&#39;t matter&quot;</li></ul></li><li><p><strong>Understand Dependencies</strong></p><ul><li>What other components does this need?</li><li>What settings, config, environment?</li><li>What assumptions does it make?</li></ul></li></ol><h3 id="phase-3-hypothesis-and-testing" tabindex="-1">Phase 3: Hypothesis and Testing <a class="header-anchor" href="#phase-3-hypothesis-and-testing" aria-label="Permalink to &quot;Phase 3: Hypothesis and Testing&quot;">​</a></h3><p><strong>Scientific method:</strong></p><ol><li><p><strong>Form Single Hypothesis</strong></p><ul><li>State clearly: &quot;I think X is the root cause because Y&quot;</li><li>Write it down</li><li>Be specific, not vague</li></ul></li><li><p><strong>Test Minimally</strong></p><ul><li>Make the SMALLEST possible change to test hypothesis</li><li>One variable at a time</li><li>Don&#39;t fix multiple things at once</li></ul></li><li><p><strong>Verify Before Continuing</strong></p><ul><li>Did it work? Yes → Phase 4</li><li>Didn&#39;t work? Form NEW hypothesis</li><li>DON&#39;T add more fixes on top</li></ul></li><li><p><strong>When You Don&#39;t Know</strong></p><ul><li>Say &quot;I don&#39;t understand X&quot;</li><li>Don&#39;t pretend to know</li><li>Ask for help</li><li>Research more</li></ul></li></ol><h3 id="phase-4-implementation" tabindex="-1">Phase 4: Implementation <a class="header-anchor" href="#phase-4-implementation" aria-label="Permalink to &quot;Phase 4: Implementation&quot;">​</a></h3><p><strong>Fix the root cause, not the symptom:</strong></p><ol><li><p><strong>Create Failing Test Case</strong></p><ul><li>Simplest possible reproduction</li><li>Automated test if possible</li><li>MUST have before fixing</li><li>Use the <code>cm-tdd</code> skill for writing proper failing tests</li></ul></li><li><p><strong>Implement Single Fix</strong></p><ul><li>Address the root cause identified</li><li>ONE change at a time</li><li>No &quot;while I&#39;m here&quot; improvements</li><li>No bundled refactoring</li></ul></li><li><p><strong>Verify Fix</strong></p><ul><li>Test passes now?</li><li>No other tests broken?</li><li>Issue actually resolved?</li></ul></li><li><p><strong>If Fix Doesn&#39;t Work</strong></p><ul><li>STOP</li><li>Count: How many fixes have you tried?</li><li>If &lt; 3: Return to Phase 1, re-analyze with new information</li><li><strong>If ≥ 3: STOP and question the architecture (step 5 below)</strong></li><li>DON&#39;T attempt Fix #4 without architectural discussion</li></ul></li><li><p><strong>If 3+ Fixes Failed: Question Architecture</strong></p><p><strong>Pattern indicating architectural problem:</strong></p><ul><li>Each fix reveals new shared state/coupling/problem in different place</li><li>Fixes require &quot;massive refactoring&quot; to implement</li><li>Each fix creates new symptoms elsewhere</li></ul><p><strong>Discuss with your human partner before attempting more fixes</strong></p><p>This is NOT a failed hypothesis - this is a wrong architecture.</p></li></ol><h2 id="red-flags-stop-and-follow-process" tabindex="-1">Red Flags - STOP and Follow Process <a class="header-anchor" href="#red-flags-stop-and-follow-process" aria-label="Permalink to &quot;Red Flags - STOP and Follow Process&quot;">​</a></h2><p>If you catch yourself thinking:</p><ul><li>&quot;Quick fix for now, investigate later&quot;</li><li>&quot;Just try changing X and see if it works&quot;</li><li>&quot;Add multiple changes, run tests&quot;</li><li>&quot;Skip the test, I&#39;ll manually verify&quot;</li><li>&quot;It&#39;s probably X, let me fix that&quot;</li><li>&quot;I don&#39;t fully understand but this might work&quot;</li><li>&quot;Pattern says X but I&#39;ll adapt it differently&quot;</li><li>&quot;Here are the main problems: [lists fixes without investigation]&quot;</li><li>Proposing solutions before tracing data flow</li><li><strong>&quot;One more fix attempt&quot; (when already tried 2+)</strong></li><li><strong>Each fix reveals new problem in different place</strong></li></ul><p><strong>ALL of these mean: STOP. Return to Phase 1.</strong></p><p><strong>When you see these user signals:</strong> STOP. Return to Phase 1.</p><ul><li>&quot;Stop guessing&quot;</li><li>&quot;Ultrathink this&quot;</li></ul><h2 id="common-rationalizations" tabindex="-1">Common Rationalizations <a class="header-anchor" href="#common-rationalizations" aria-label="Permalink to &quot;Common Rationalizations&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Excuse</th><th>Reality</th></tr></thead><tbody><tr><td>&quot;Issue is simple, don&#39;t need process&quot;</td><td>Simple issues have root causes too. Process is fast for simple bugs.</td></tr><tr><td>&quot;Emergency, no time for process&quot;</td><td>Systematic debugging is FASTER than guess-and-check thrashing.</td></tr><tr><td>&quot;Just try this first, then investigate&quot;</td><td>First fix sets the pattern. Do it right from the start.</td></tr><tr><td>&quot;I&#39;ll write test after confirming fix works&quot;</td><td>Untested fixes don&#39;t stick. Test first proves it.</td></tr><tr><td>&quot;Multiple fixes at once saves time&quot;</td><td>Can&#39;t isolate what worked. Causes new bugs.</td></tr></tbody></table><h2 id="quick-reference" tabindex="-1">Quick Reference <a class="header-anchor" href="#quick-reference" aria-label="Permalink to &quot;Quick Reference&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Phase</th><th>Key Activities</th><th>Success Criteria</th></tr></thead><tbody><tr><td><strong>1. Root Cause</strong></td><td>Read errors, reproduce, check changes, gather evidence</td><td>Understand WHAT and WHY</td></tr><tr><td><strong>2. Pattern</strong></td><td>Find working examples, compare</td><td>Identify differences</td></tr><tr><td><strong>3. Hypothesis</strong></td><td>Form theory, test minimally</td><td>Confirmed or new hypothesis</td></tr><tr><td><strong>4. Implementation</strong></td><td>Create test, fix, verify</td><td>Bug resolved, tests pass</td></tr></tbody></table><h2 id="when-process-reveals-no-root-cause" tabindex="-1">When Process Reveals &quot;No Root Cause&quot; <a class="header-anchor" href="#when-process-reveals-no-root-cause" aria-label="Permalink to &quot;When Process Reveals &quot;No Root Cause&quot;&quot;">​</a></h2><p>If systematic investigation reveals issue is truly environmental, timing-dependent, or external:</p><ol><li>You&#39;ve completed the process</li><li>Document what you investigated</li><li>Implement appropriate handling (retry, timeout, error message)</li><li>Add monitoring/logging for future investigation</li></ol><p><strong>But:</strong> 95% of &quot;no root cause&quot; cases are incomplete investigation.</p><h2 id="integration" tabindex="-1">Integration <a class="header-anchor" href="#integration" aria-label="Permalink to &quot;Integration&quot;">​</a></h2><p><strong>Related skills:</strong></p><ul><li><strong>cm-tdd</strong> - For creating failing test case (Phase 4, Step 1)</li><li><strong>cm-quality-gate</strong> - Verify fix worked before claiming success</li></ul>`,48)])])}const g=t(a,[["render",o]]);export{c as __pageData,g as default};
